changeSet.sql:
CREATE MATERIALIZED VIEW mv_patient_health_dashboard AS SELECT phs.tenant_id, phs.patient_id, phs.latest_health_score, phs.health_trend, phs.risk_level, phs.risk_score, phs.open_care_gaps_count, phs.urgent_gaps_count, phs.active_alerts_count, phs.critical_alerts_count, CASE WHEN phs.risk_level = 'high' THEN 3 WHEN phs.risk_level = 'medium' THEN 2 WHEN phs.risk_level = 'low' THEN 1 ELSE 0 END AS risk_category_order, ( COALESCE(phs.urgent_gaps_count * 10, 0) + COALESCE(phs.critical_alerts_count * 5, 0) + CASE WHEN phs.risk_level = 'high' THEN 3 WHEN phs.risk_level = 'medium' THEN 1 ELSE 0 END ) AS priority_score, phs.last_updated_at FROM patient_health_summary phs WHERE phs.latest_health_score IS NOT NULL;
CREATE INDEX idx_mv_phd_tenant_priority ON mv_patient_health_dashboard(tenant_id, priority_score DESC);
CREATE INDEX idx_mv_phd_tenant_risk ON mv_patient_health_dashboard(tenant_id, risk_category_order DESC);

CREATE OR REPLACE FUNCTION refresh_patient_health_dashboard()
RETURNS void
LANGUAGE plpgsql
AS $function$
BEGIN
    REFRESH MATERIALIZED VIEW CONCURRENTLY mv_patient_health_dashboard;
END;
$function$;
